import { ipcMain, BrowserWindow } from 'electron';
import { randomUUID } from 'crypto';
import { localDockerService } from '../services/LocalDockerService';
import { SSHService } from '../services/SSHService';
import { dockerfileGenerator } from '../services/DockerfileGenerator';

// Create a dedicated SSH service instance for local docker operations
const sshService = new SSHService();
import {
  IPC_CHANNELS,
  LocalDockerBuildSchema,
  LocalDockerStreamSchema,
  LocalDockerDeploySchema,
  LocalDockerCancelSchema,
  LocalDockerCleanupSchema,
  LocalDockerGetBuildsSchema,
  LocalDockerValidateContextSchema,
  ApiResult,
  LocalDockerCheckResult,
  LocalDockerBuildProgress,
  LocalDockerBuildLog,
  LocalDockerUploadProgress,
  BuildContextValidation,
  LocalBuildRecord,
  LocalDockerDeployResult,
} from './types';

let mainWindow: BrowserWindow | null = null;

export function setLocalDockerMainWindow(window: BrowserWindow) {
  mainWindow = window;
}

export function registerLocalDockerHandlers() {
  // Check Docker availability
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_CHECK,
    async (): Promise<ApiResult<LocalDockerCheckResult>> => {
      try {
        const result = await localDockerService.checkDockerAvailable();
        return { success: true, data: result };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Validate build context
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_VALIDATE_CONTEXT,
    async (_event, input): Promise<ApiResult<BuildContextValidation>> => {
      try {
        const { projectPath } = LocalDockerValidateContextSchema.parse(input);
        const result = await localDockerService.validateBuildContext(projectPath);
        return { success: true, data: result };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Test git repository access (lightweight check using ls-remote)
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_TEST_GIT_ACCESS,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { repoUrl, sshKeyPath } = input as {
          repoUrl: string;
          sshKeyPath?: string;
        };
        const result = await localDockerService.testGitAccess({
          repoUrl,
          sshKeyPath,
        });
        if (result.success) {
          return { success: true, data: undefined };
        } else {
          return { success: false, error: result.error };
        }
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Clone repository locally for building
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_CLONE,
    async (_event, input): Promise<ApiResult<{ localPath: string }>> => {
      try {
        const { repoUrl, branch, sshKeyPath } = input as {
          repoUrl: string;
          branch?: string;
          sshKeyPath?: string;
        };
        const result = await localDockerService.cloneRepository({
          repoUrl,
          branch,
          sshKeyPath,
        });
        if (result.success) {
          return { success: true, data: { localPath: result.localPath } };
        } else {
          return { success: false, error: result.error };
        }
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Cleanup cloned repository
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_CLEANUP_CLONE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { localPath } = input as { localPath: string };
        await localDockerService.cleanupClonedRepo(localPath);
        return { success: true, data: undefined };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Build Docker image locally
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_BUILD,
    async (_event, input): Promise<ApiResult<{ buildId: string; success: boolean; imageId?: string; imageSize?: number; error?: string }>> => {
      try {
        const options = LocalDockerBuildSchema.parse(input);
        const buildId = options.buildId || randomUUID();

        // Set up progress listeners
        const progressHandler = (progress: LocalDockerBuildProgress) => {
          if (progress.buildId === buildId && mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_PROGRESS, progress);
          }
        };

        const logHandler = (log: LocalDockerBuildLog) => {
          if (log.buildId === buildId && mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_LOG, log);
          }
        };

        localDockerService.on('build-progress', progressHandler);
        localDockerService.on('build-log', logHandler);

        try {
          const result = await localDockerService.buildImage({
            buildId,
            projectPath: options.projectPath,
            imageName: options.imageName,
            imageTag: options.imageTag,
            platform: options.platform,
            noCache: options.noCache,
            dockerfilePath: options.dockerfilePath,
            buildArgs: options.buildArgs as Record<string, string> | undefined,
          });

          return {
            success: result.success,
            data: { buildId, ...result },
          };
        } finally {
          localDockerService.off('build-progress', progressHandler);
          localDockerService.off('build-log', logHandler);
        }
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Stream image to server
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_STREAM,
    async (_event, input): Promise<ApiResult<{ streamId: string; success: boolean; error?: string }>> => {
      try {
        const options = LocalDockerStreamSchema.parse(input);
        const streamId = options.streamId || randomUUID();

        // Set up progress listener
        const progressHandler = (progress: LocalDockerUploadProgress) => {
          if (progress.streamId === streamId && mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_UPLOAD_PROGRESS, progress);
          }
        };

        const logHandler = (log: LocalDockerBuildLog) => {
          if (log.buildId === streamId && mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_LOG, log);
          }
        };

        localDockerService.on('upload-progress', progressHandler);
        localDockerService.on('build-log', logHandler);

        try {
          const result = await localDockerService.streamImageToServer({
            streamId,
            imageName: options.imageName,
            imageTag: options.imageTag,
            serverId: options.serverId,
            sshService,
            useCompression: options.useCompression,
          });

          return {
            success: result.success,
            data: { streamId, ...result },
          };
        } finally {
          localDockerService.off('upload-progress', progressHandler);
          localDockerService.off('build-log', logHandler);
        }
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Full deployment with local build
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_DEPLOY,
    async (_event, input): Promise<ApiResult<LocalDockerDeployResult>> => {
      try {
        const options = LocalDockerDeploySchema.parse(input);
        const deploymentId = randomUUID();
        const buildId = randomUUID();
        const imageName = `servercompass/${options.appName}`;
        const imageTag = Date.now().toString();

        const emitProgress = (progress: LocalDockerBuildProgress) => {
          if (mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_PROGRESS, {
              ...progress,
              buildId,
            });
          }
        };

        const emitLog = (level: 'info' | 'warn' | 'error', message: string) => {
          if (mainWindow) {
            mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_LOG, {
              buildId,
              level,
              message,
              timestamp: Date.now(),
            });
          }
        };

        // Save initial build record
        localDockerService.saveBuildRecord({
          id: buildId,
          deploymentId,
          serverId: options.serverId,
          appName: options.appName,
          projectPath: options.projectPath,
          imageName,
          imageTag,
          status: 'pending',
          dockerfileGenerated: false,
          platform: options.platform,
          buildArgs: options.buildArgs as Record<string, string> | undefined,
          useCompression: options.useCompression,
        });

        try {
          // Step 1: Check local Docker
          emitProgress({
            buildId,
            phase: 'analyzing',
            step: 1,
            totalSteps: 6,
            message: 'Checking Docker availability...',
            percentage: 5,
          });

          const dockerCheck = await localDockerService.checkDockerAvailable();
          if (!dockerCheck.available) {
            throw new Error(dockerCheck.error || 'Docker is not available on your machine');
          }

          // Step 2: Validate build context and generate Dockerfile if needed
          emitProgress({
            buildId,
            phase: 'analyzing',
            step: 2,
            totalSteps: 6,
            message: 'Analyzing project...',
            percentage: 10,
          });

          const validation = await localDockerService.validateBuildContext(options.projectPath);
          let dockerfilePath = options.dockerfilePath;
          let dockerfileGenerated = false;

          if (!validation.hasDockerfile && !dockerfilePath) {
            emitProgress({
              buildId,
              phase: 'generating',
              step: 2,
              totalSteps: 6,
              message: 'Generating Dockerfile...',
              percentage: 15,
            });

            const generated = await dockerfileGenerator.generateDockerfile(options.projectPath);
            dockerfilePath = generated.dockerfilePath;
            dockerfileGenerated = true;
            emitLog('info', `Generated Dockerfile for ${generated.projectType} project`);
          }

          // Update build record with Dockerfile info
          localDockerService.updateBuildRecord(buildId, {
            dockerfileGenerated,
            dockerfilePath,
          });

          // Step 3: Build image locally
          const buildStartedAt = new Date().toISOString();
          localDockerService.updateBuildRecord(buildId, {
            status: 'building',
            buildStartedAt,
          });

          emitProgress({
            buildId,
            phase: 'building',
            step: 3,
            totalSteps: 6,
            message: 'Building Docker image...',
            percentage: 20,
          });

          // Forward build progress
          const buildProgressHandler = (progress: LocalDockerBuildProgress) => {
            if (progress.buildId === buildId && mainWindow) {
              // Map percentage to 20-60 range
              const mappedPercentage = 20 + Math.round((progress.percentage || 0) * 0.4);
              mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_PROGRESS, {
                ...progress,
                percentage: mappedPercentage,
              });
            }
          };

          localDockerService.on('build-progress', buildProgressHandler);

          const buildResult = await localDockerService.buildImage({
            buildId,
            projectPath: options.projectPath,
            dockerfilePath,
            imageName,
            imageTag,
            platform: options.platform,
            buildArgs: options.buildArgs as Record<string, string> | undefined,
            noCache: options.noCache,
          });

          localDockerService.off('build-progress', buildProgressHandler);

          if (!buildResult.success) {
            throw new Error(buildResult.error || 'Build failed');
          }

          const buildCompletedAt = new Date().toISOString();
          const buildDuration = Math.round(
            (new Date(buildCompletedAt).getTime() - new Date(buildStartedAt).getTime()) / 1000
          );

          localDockerService.updateBuildRecord(buildId, {
            buildCompletedAt,
            buildDuration,
            imageSize: buildResult.imageSize,
          });

          emitLog('info', `Build completed in ${buildDuration}s, image size: ${buildResult.imageSize ? Math.round(buildResult.imageSize / 1024 / 1024) + 'MB' : 'unknown'}`);

          // Step 4: Stream image to server
          const uploadStartedAt = new Date().toISOString();
          localDockerService.updateBuildRecord(buildId, {
            status: 'uploading',
            uploadStartedAt,
          });

          emitProgress({
            buildId,
            phase: 'uploading',
            step: 4,
            totalSteps: 6,
            message: 'Uploading image to server...',
            percentage: 60,
          });

          // Forward upload progress
          const uploadProgressHandler = (progress: LocalDockerUploadProgress) => {
            if (mainWindow) {
              // Map percentage to 60-80 range
              const mappedPercentage = 60 + Math.round(progress.percentage * 0.2);
              mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_UPLOAD_PROGRESS, progress);
              mainWindow.webContents.send(IPC_CHANNELS.LOCAL_DOCKER_BUILD_PROGRESS, {
                buildId,
                phase: 'uploading',
                step: 4,
                totalSteps: 6,
                message: `Uploading: ${Math.round(progress.bytesTransferred / 1024 / 1024)}MB / ${Math.round(progress.totalBytes / 1024 / 1024)}MB`,
                percentage: mappedPercentage,
              });
            }
          };

          localDockerService.on('upload-progress', uploadProgressHandler);

          const streamResult = await localDockerService.streamImageToServer({
            streamId: buildId,
            imageName,
            imageTag,
            serverId: options.serverId,
            sshService,
            useCompression: options.useCompression,
          });

          localDockerService.off('upload-progress', uploadProgressHandler);

          if (!streamResult.success) {
            throw new Error(streamResult.error || 'Upload failed');
          }

          const uploadCompletedAt = new Date().toISOString();
          const uploadDuration = Math.round(
            (new Date(uploadCompletedAt).getTime() - new Date(uploadStartedAt).getTime()) / 1000
          );

          localDockerService.updateBuildRecord(buildId, {
            uploadCompletedAt,
            uploadDuration,
          });

          emitLog('info', `Upload completed in ${uploadDuration}s`);

          // Step 5: Deploy container on server
          localDockerService.updateBuildRecord(buildId, { status: 'deploying' });

          emitProgress({
            buildId,
            phase: 'deploying',
            step: 5,
            totalSteps: 6,
            message: 'Starting container...',
            percentage: 85,
          });

          const containerName = `sc-${options.appName}`;
          const fullImageName = `${imageName}:${imageTag}`;
          const client = await sshService.connect(options.serverId);

          // Stop and remove existing container
          await sshService.executeCommand(client, `docker stop ${containerName} 2>/dev/null || true`);
          await sshService.executeCommand(client, `docker rm ${containerName} 2>/dev/null || true`);

          // Build docker run command
          let runCommand = `docker run -d --name ${containerName} --restart unless-stopped`;
          runCommand += ` -p ${options.port}:${options.port}`;

          // Add environment variables
          if (options.envVars) {
            for (const [key, value] of Object.entries(options.envVars as Record<string, string>)) {
              // Escape special characters in values
              const escapedValue = String(value).replace(/"/g, '\\"').replace(/\$/g, '\\$');
              runCommand += ` -e ${key}="${escapedValue}"`;
            }
          }

          runCommand += ` ${fullImageName}`;

          const runResult = await sshService.executeCommand(client, runCommand);
          if (runResult.exitCode !== 0) {
            throw new Error(`Failed to start container: ${runResult.stderr}`);
          }

          emitLog('info', `Container ${containerName} started successfully`);

          // Step 6: Verify deployment
          emitProgress({
            buildId,
            phase: 'verifying',
            step: 6,
            totalSteps: 6,
            message: 'Verifying deployment...',
            percentage: 95,
          });

          // Simple health check - verify container is running
          let healthy = false;
          let healthMessage = '';

          for (let attempt = 1; attempt <= 3; attempt++) {
            await new Promise(resolve => setTimeout(resolve, 2000));

            const statusResult = await sshService.executeCommand(
              client,
              `docker inspect --format='{{.State.Status}}' ${containerName}`
            );

            if (statusResult.stdout.trim() === 'running') {
              healthy = true;
              healthMessage = 'Container is running';
              break;
            }

            if (attempt === 3) {
              // Get container logs for debugging
              const logsResult = await sshService.executeCommand(
                client,
                `docker logs --tail 20 ${containerName} 2>&1`
              );
              healthMessage = `Container not running. Logs:\n${logsResult.stdout}`;
            }
          }

          // Get server IP for URL
          const server = await sshService.executeCommand(client, 'hostname -I | awk \'{print $1}\'');
          const serverIp = server.stdout.trim();

          // Cleanup local image if requested
          if (options.cleanupLocalImage) {
            emitProgress({
              buildId,
              phase: 'cleanup',
              step: 6,
              totalSteps: 6,
              message: 'Cleaning up local image...',
              percentage: 98,
            });
            await localDockerService.cleanupLocalImage(imageName, imageTag);
          }

          // Cleanup generated Dockerfile
          if (dockerfileGenerated && dockerfilePath) {
            try {
              const fs = await import('fs/promises');
              await fs.unlink(dockerfilePath);
            } catch {
              // Ignore cleanup errors
            }
          }

          // Update final status
          localDockerService.updateBuildRecord(buildId, {
            status: healthy ? 'completed' : 'completed', // Still mark as completed even if health check uncertain
          });

          emitProgress({
            buildId,
            phase: 'deploying',
            step: 6,
            totalSteps: 6,
            message: 'Deployment completed!',
            percentage: 100,
          });

          const url = options.domain ? `https://${options.domain}` : `http://${serverIp}:${options.port}`;

          return {
            success: true,
            data: {
              success: true,
              deploymentId,
              buildId,
              imageName: fullImageName,
              containerName,
              url,
              healthCheck: {
                healthy,
                message: healthMessage,
              },
            },
          };

        } catch (error: any) {
          // Update build record with error
          localDockerService.updateBuildRecord(buildId, {
            status: 'failed',
            errorMessage: error.message,
          });

          // Cleanup on failure
          localDockerService.cancelBuild(buildId);
          localDockerService.cancelStream(buildId);

          emitLog('error', error.message);

          return { success: false, error: error.message };
        }
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Cancel build or stream
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_CANCEL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { buildId, streamId } = LocalDockerCancelSchema.parse(input);

        if (buildId) {
          localDockerService.cancelBuild(buildId);
          localDockerService.updateBuildRecord(buildId, { status: 'cancelled' });
        }
        if (streamId) {
          localDockerService.cancelStream(streamId);
        }

        return { success: true };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Cleanup local image
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_CLEANUP,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { imageName, imageTag } = LocalDockerCleanupSchema.parse(input);
        await localDockerService.cleanupLocalImage(imageName, imageTag);
        return { success: true };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );

  // Get build records
  ipcMain.handle(
    IPC_CHANNELS.LOCAL_DOCKER_GET_BUILDS,
    async (_event, input): Promise<ApiResult<LocalBuildRecord[]>> => {
      try {
        const { serverId, limit } = LocalDockerGetBuildsSchema.parse(input || {});
        const records = localDockerService.getBuildRecords(serverId, limit);
        return { success: true, data: records };
      } catch (error: any) {
        return { success: false, error: error.message };
      }
    }
  );
}
